content.content:
1	/* Flux - Multi-Theme System */
2	
3	/* =============================================
4	   BASE VARIABLES (shared across all themes)
5	   ============================================= */
6	:root {
7	  --radius: 8px;
8	  --transition: 0.2s;
9	  --danger: #ff4444;
10	  --warning: #ff9800;
11	}
12	
13	/* =============================================
14	   THEME-SPECIFIC VARIABLES
15	   (accent colors, fonts, effects)
16	   ============================================= */
17	
18	/* Cyberpunk (default) - Neon glow, high contrast, monospace */
19	[data-theme="cyberpunk"] {
20	  --accent: #00ff88;
21	  --accent-dim: #00cc6a;
22	  --font-family: 'Courier New', monospace;
23	  --glow: 0 0 20px rgba(0, 255, 136, 0.3);
24	  --shadow: none;
25	}
26	
27	/* Material - Soft shadows, calm, system font */
28	[data-theme="material"] {
29	  --accent: #009688;
30	  --accent-dim: #00796b;
31	  --font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
32	  --glow: none;
33	  --shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
34	}
35	
36	/* Ocean - Cool, clean, system font */
37	[data-theme="ocean"] {
38	  --accent: #2196f3;
39	  --accent-dim: #1976d2;
40	  --font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
41	  --glow: none;
42	  --shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
43	}
44	
45	/* Ember - Warm, energetic, monospace */
46	[data-theme="ember"] {
47	  --accent: #ff7043;
48	  --accent-dim: #f4511e;
49	  --font-family: 'Courier New', monospace;
50	  --glow: 0 0 20px rgba(255, 112, 67, 0.3);
51	  --shadow: none;
52	}
53	
54	/* =============================================
55	   MODE-SPECIFIC VARIABLES
56	   (backgrounds, text colors)
57	   ============================================= */
58	
59	/* Dark mode */
60	[data-mode="dark"] {
61	  --bg-primary: #0a0a0a;
62	  --bg-secondary: #111111;
63	  --bg-card: #1a1a1a;
64	  --text-primary: #e0e0e0;
65	  --text-secondary: #aaaaaa;
66	  --border: #333333;
67	}
68	
69	/* Light mode */
70	[data-mode="light"] {
71	  --bg-primary: #f5f5f5;
72	  --bg-secondary: #ffffff;
73	  --bg-card: #ffffff;
74	  --text-primary: #1a1a1a;
75	  --text-secondary: #666666;
76	  --border: #dddddd;
77	}
78	
79	/* =============================================
80	   THEME + MODE COMBINATION OVERRIDES
81	   (accent adjustments for light backgrounds)
82	   ============================================= */
83	
84	/* Cyberpunk light - darker green for readability */
85	[data-theme="cyberpunk"][data-mode="light"] {
86	  --accent: #00994d;
87	  --accent-dim: #007a3d;
88	  --glow: 0 0 20px rgba(0, 153, 77, 0.2);
89	}
90	
91	/* Material light - slightly darker teal */
92	[data-theme="material"][data-mode="light"] {
93	  --accent: #00796b;
94	  --accent-dim: #00695c;
95	  --shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
96	}
97	
98	/* Ocean light - slightly darker blue */
99	[data-theme="ocean"][data-mode="light"] {
100	  --accent: #1976d2;
101	  --accent-dim: #1565c0;
102	  --shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
103	}
104	
105	/* Ember light - slightly darker orange */
106	[data-theme="ember"][data-mode="light"] {
107	  --accent: #f4511e;
108	  --accent-dim: #e64a19;
109	  --glow: 0 0 20px rgba(244, 81, 30, 0.15);
110	}
111	
112	/* =============================================
113	   GLOBAL RESET
114	   ============================================= */
115	* {
116	  margin: 0;
117	  padding: 0;
118	  box-sizing: border-box;
119	}
120	
121	body {
122	  font-family: var(--font-family);
123	  background: var(--bg-primary);
124	  color: var(--text-primary);
125	  min-height: 100vh;
126	  display: flex;
127	  flex-direction: column;
128	  -webkit-font-smoothing: antialiased;
129	  overflow-x: hidden;
130	}
131	
132	/* =============================================
133	   HEADER
134	   ============================================= */
135	header {
136	  background: var(--bg-secondary);
137	  padding: 1rem;
138	  text-align: center;
139	  border-bottom: 1px solid var(--accent);
140	  position: sticky;
141	  top: 0;
142	  z-index: 100;
143	  box-shadow: var(--shadow);
144	}
145	
146	.settings-btn {
147	  position: absolute;
148	  top: 50%;
149	  right: 1rem;
150	  transform: translateY(-50%);
151	  background: transparent;
152	  border: 1px solid var(--border);
153	  color: var(--text-secondary);
154	  width: 36px;
155	  height: 36px;
156	  border-radius: 50%;
157	  cursor: pointer;
158	  display: flex;
159	  align-items: center;
160	  justify-content: center;
161	  font-size: 1.2rem;
162	  transition: all var(--transition);
163	}
164	
165	.settings-btn:hover {
166	  border-color: var(--accent);
167	  color: var(--accent);
168	}
169	
170	header h1 {
171	  font-size: 1.5rem;
172	  letter-spacing: 0.3em;
173	  color: var(--accent);
174	  text-shadow: var(--glow);
175	}
176	
177	#day-counter {
178	  font-size: 1rem;
179	  color: var(--text-secondary);
180	  margin-top: 0.5rem;
181	}
182	
183	#day-counter span {
184	  color: var(--accent);
185	  font-weight: bold;
186	}
187	
188	/* =============================================
189	   SESSION PROGRESS BAR
190	   ============================================= */
191	#session-progress {
192	  position: absolute;
193	  bottom: 0;
194	  left: 0;
195	  right: 0;
196	  height: 3px;
197	  background: transparent;
198	}
199	
200	#session-progress-bar {
201	  height: 100%;
202	  width: 0%;
203	  background: var(--accent);
204	  box-shadow: var(--glow);
205	  transition: width 0.4s ease;
206	}
207	
208	/* =============================================
209	   MAIN CONTENT
210	   ============================================= */
211	main {
212	  flex: 1;
213	  padding: 1rem;
214	  overflow-y: auto;
215	  padding-bottom: 100px;
216	}
217	
218	.card {
219	  background: var(--bg-card);
220	  border: 1px solid var(--border);
221	  border-radius: var(--radius);
222	  padding: 1rem;
223	  margin-bottom: 1rem;
224	  box-shadow: var(--shadow);
225	}
226	
227	#workout-header {
228	  border-bottom: 1px solid var(--border);
229	  padding-bottom: 1rem;
230	  margin-bottom: 1rem;
231	}
232	
233	#workout-name {
234	  font-size: 1.3rem;
235	  color: var(--accent);
236	  margin-bottom: 0.25rem;
237	}
238	
239	#workout-focus {
240	  font-size: 1rem;
241	  color: var(--text-secondary);
242	}
243	
244	/* =============================================
245	   EXERCISE ITEMS
246	   ============================================= */
247	.exercise {
248	  background: var(--bg-secondary);
249	  border: 1px solid var(--border);
250	  border-radius: 6px;
251	  padding: 1rem;
252	  margin-bottom: 0.75rem;
253	  box-shadow: var(--shadow);
254	}
255	
256	.exercise-header {
257	  display: flex;
258	  justify-content: space-between;
259	  align-items: flex-start;
260	  margin-bottom: 0.5rem;
261	}
262	
263	.exercise-name {
264	  font-size: 1.1rem;
265	  font-weight: bold;
266	  color: var(--text-primary);
267	  flex: 1;
268	}
269	
270	.video-btn {
271	  background: transparent;
272	  border: 1px solid var(--accent);
273	  color: var(--accent);
274	  padding: 0.25rem 0.5rem;
275	  font-size: 0.9rem;
276	  border-radius: 4px;
277	  cursor: pointer;
278	  font-family: inherit;
279	  transition: all var(--transition);
280	}
281	
282	.video-btn:hover {
283	  background: var(--accent);
284	  color: var(--bg-primary);
285	}
286	
287	.video-btn:disabled {
288	  opacity: 0.3;
289	  cursor: not-allowed;
290	}
291	
292	.exercise-details {
293	  display: flex;
294	  gap: 1rem;
295	  font-size: 1rem;
296	  color: var(--text-secondary);
297	  margin-bottom: 0.5rem;
298	}
299	
300	.exercise-details span {
301	  display: flex;
302	  align-items: center;
303	  gap: 0.25rem;
304	}
305	
306	.exercise-note {
307	  font-size: 0.95rem;
308	  color: var(--accent-dim);
309	  font-style: italic;
310	  padding-top: 0.5rem;
311	  border-top: 1px dashed var(--border);
312	}
313	
314	/* =============================================
315	   COMPLETED EXERCISE STATE
316	   ============================================= */
317	.exercise.completed {
318	  border-left: 3px solid var(--accent);
319	  opacity: 0.85;
320	}
321	
322	.exercise.completed .exercise-name {
323	  color: var(--accent);
324	}
325	
326	/* Done Button */
327	.done-btn {
328	  background: transparent;
329	  border: 1px solid var(--accent);
330	  color: var(--accent);
331	  padding: 0.4rem 0.75rem;
332	  font-size: 0.85rem;
333	  font-family: inherit;
334	  border-radius: 4px;
335	  cursor: pointer;
336	  transition: all var(--transition);
337	  text-transform: uppercase;
338	  letter-spacing: 0.05em;
339	  font-weight: bold;
340	}
341	
342	.done-btn:hover {
343	  background: var(--accent);
344	  color: var(--bg-primary);
345	}
346	
347	.done-btn.is-done {
348	  background: var(--accent);
349	  color: var(--bg-primary);
350	}
351	
352	/* =============================================
353	   WEIGHT INPUT
354	   ============================================= */
355	.weight-input {
356	  display: flex;
357	  align-items: center;
358	  flex-wrap: wrap;
359	  gap: 0.5rem;
360	  margin-top: 0.75rem;
361	  padding-top: 0.75rem;
362	  border-top: 1px solid var(--border);
363	}
364	
365	.weight-input label {
366	  font-size: 0.95rem;
367	  color: var(--text-secondary);
368	}
369	
370	.weight-input input {
371	  background: var(--bg-primary);
372	  border: 1px solid var(--border);
373	  color: var(--text-primary);
374	  padding: 0.5rem;
375	  width: 80px;
376	  font-family: inherit;
377	  font-size: 1.1rem;
378	  border-radius: 4px;
379	  text-align: center;
380	}
381	
382	.weight-input input:focus {
383	  outline: none;
384	  border-color: var(--accent);
385	  box-shadow: var(--glow);
386	}
387	
388	.weight-input .unit {
389	  font-size: 0.95rem;
390	  color: var(--text-secondary);
391	}
392	
393	/* Weight Controls (+/- buttons) */
394	.weight-controls {
395	  display: flex;
396	  align-items: center;
397	  gap: 0.5rem;
398	}
399	
400	.weight-btn {
401	  width: 32px;
402	  height: 32px;
403	  border-radius: 50%;
404	  border: 1px solid var(--accent);
405	  background: transparent;
406	  color: var(--accent);
407	  font-size: 1.2rem;
408	  font-family: inherit;
409	  cursor: pointer;
410	  display: flex;
411	  align-items: center;
412	  justify-content: center;
413	  transition: all var(--transition);
414	}
415	
416	.weight-btn:hover {
417	  background: var(--accent);
418	  color: var(--bg-primary);
419	}
420	
421	.weight-btn:active {
422	  transform: scale(0.95);
423	}
424	
425	.suggested-hint {
426	  font-size: 0.9rem;
427	  color: var(--text-secondary);
428	  font-style: italic;
429	  margin-left: 0.5rem;
430	}
431	
432	/* =============================================
433	   FEEDBACK SECTION
434	   ============================================= */
435	.feedback-section {
436	  margin-top: 0.75rem;
437	  padding-top: 0.75rem;
438	  border-top: 1px solid var(--border);
439	}
440	
441	.feedback-toggle {
442	  background: transparent;
443	  border: 1px solid var(--border);
444	  color: var(--text-secondary);
