465	}
466	
467	.feedback-section.expanded .feedback-toggle {
468	  border-color: var(--accent);
469	  color: var(--accent);
470	}
471	
472	/* Difficulty Input */
473	.difficulty-input {
474	  margin-bottom: 0.75rem;
475	}
476	
477	.difficulty-input label {
478	  font-size: 0.95rem;
479	  color: var(--text-secondary);
480	  display: block;
481	  margin-bottom: 0.5rem;
482	}
483	
484	.difficulty-buttons {
485	  display: flex;
486	  gap: 0.5rem;
487	}
488	
