  --accent: #00ff88;
  --accent-dim: #00cc6a;
  --font-family: 'Courier New', monospace;
  --glow: 0 0 20px rgba(0, 255, 136, 0.3);
  --shadow: none;
}

/* Material - Soft shadows, calm, system font */
[data-theme="material"] {
  --accent: #009688;
  --accent-dim: #00796b;
  --font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --glow: none;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

/* Ocean - Cool, clean, system font */
[data-theme="ocean"] {
  --accent: #2196f3;
  --accent-dim: #1976d2;
  --font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --glow: none;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
}

/* Ember - Warm, energetic, monospace */
[data-theme="ember"] {
  --accent: #ff7043;
  --accent-dim: #f4511e;
  --font-family: 'Courier New', monospace;
  --glow: 0 0 20px rgba(255, 112, 67, 0.3);
  --shadow: none;
}

/* =============================================
   MODE-SPECIFIC VARIABLES
   (backgrounds, text colors)
   ============================================= */

/* Dark mode */
[data-mode="dark"] {
  --bg-primary: #0a0a0a;
  --bg-secondary: #111111;
  --bg-card: #1a1a1a;
  --text-primary: #e0e0e0;
  --text-secondary: #aaaaaa;
  --border: #333333;
}

/* Light mode */
[data-mode="light"] {
  --bg-primary: #f5f5f5;
  --bg-secondary: #ffffff;
  --bg-card: #ffffff;
  --text-primary: #1a1a1a;
  --text-secondary: #666666;
  --border: #dddddd;
}

/* =============================================
   THEME + MODE COMBINATION OVERRIDES
   (accent adjustments for light backgrounds)
   ============================================= */

/* Cyberpunk light - darker green for readability */
[data-theme="cyberpunk"][data-mode="light"] {
  --accent: #00994d;
  --accent-dim: #007a3d;
  --glow: 0 0 20px rgba(0, 153, 77, 0.2);
}

/* Material light - slightly darker teal */
[data-theme="material"][data-mode="light"] {
  --accent: #00796b;
  --accent-dim: #00695c;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

/* Ocean light - slightly darker blue */
[data-theme="ocean"][data-mode="light"] {
  --accent: #1976d2;
  --accent-dim: #1565c0;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
}

/* Ember light - slightly darker orange */
[data-theme="ember"][data-mode="light"] {
  --accent: #f4511e;
  --accent-dim: #e64a19;
  --glow: 0 0 20px rgba(244, 81, 30, 0.15);
}

/* =============================================
   GLOBAL RESET
   ============================================= */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: var(--font-family);
  background: var(--bg-primary);
  color: var(--text-primary);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  -webkit-font-smoothing: antialiased;
}

/* =============================================
   HEADER
   ============================================= */
header {
  background: var(--bg-secondary);
  padding: 1rem;
  text-align: center;
  border-bottom: 1px solid var(--accent);
  position: sticky;
  top: 0;
  z-index: 100;
  box-shadow: var(--shadow);
}

.settings-btn {
  position: absolute;
  top: 50%;
  right: 1rem;
  transform: translateY(-50%);
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  width: 36px;
  height: 36px;
  border-radius: 50%;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.2rem;
  transition: all var(--transition);
}

.settings-btn:hover {
  border-color: var(--accent);
  color: var(--accent);
}

header h1 {
  font-size: 1.5rem;
  letter-spacing: 0.3em;
  color: var(--accent);
  text-shadow: var(--glow);
}

#day-counter {
  font-size: 1rem;
  color: var(--text-secondary);
  margin-top: 0.5rem;
}

#day-counter span {
  color: var(--accent);
  font-weight: bold;
}

/* =============================================
   SESSION PROGRESS BAR
   ============================================= */
#session-progress {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: transparent;
}

#session-progress-bar {
  height: 100%;
  width: 0%;
  background: var(--accent);
  box-shadow: var(--glow);
  transition: width 0.4s ease;
}

/* =============================================
   MAIN CONTENT
   ============================================= */
main {
  flex: 1;
  padding: 1rem;
  overflow-y: auto;
  padding-bottom: 100px;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1rem;
  margin-bottom: 1rem;
  box-shadow: var(--shadow);
}

#workout-header {
  border-bottom: 1px solid var(--border);
  padding-bottom: 1rem;
  margin-bottom: 1rem;
}

#workout-name {
  font-size: 1.3rem;
  color: var(--accent);
  margin-bottom: 0.25rem;
}

#workout-focus {
  font-size: 1rem;
  color: var(--text-secondary);
}

/* =============================================
   EXERCISE ITEMS
   ============================================= */
.exercise {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 1rem;
  margin-bottom: 0.75rem;
  box-shadow: var(--shadow);
}

.exercise-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 0.5rem;
}

.exercise-name {
  font-size: 1.1rem;
  font-weight: bold;
  color: var(--text-primary);
  flex: 1;
}

.video-btn {
  background: transparent;
  border: 1px solid var(--accent);
  color: var(--accent);
  padding: 0.25rem 0.5rem;
  font-size: 0.9rem;
  border-radius: 4px;
  cursor: pointer;
  font-family: inherit;
  transition: all var(--transition);
}

.video-btn:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.video-btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

.exercise-details {
  display: flex;
  gap: 1rem;
  font-size: 1rem;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
}

.exercise-details span {
  display: flex;
  align-items: center;
  gap: 0.25rem;
}

.exercise-note {
  font-size: 0.95rem;
  color: var(--accent-dim);
  font-style: italic;
  padding-top: 0.5rem;
  border-top: 1px dashed var(--border);
}

/* =============================================
   COMPLETED EXERCISE STATE
   ============================================= */
.exercise.completed {
  border-left: 3px solid var(--accent);
  opacity: 0.85;
}

.exercise.completed .exercise-name {
  color: var(--accent);
}

/* Done Button */
.done-btn {
  background: transparent;
  border: 1px solid var(--accent);
  color: var(--accent);
  padding: 0.4rem 0.75rem;
  font-size: 0.85rem;
  font-family: inherit;
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: bold;
}

.done-btn:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.done-btn.is-done {
  background: var(--accent);
  color: var(--bg-primary);
}

/* =============================================
   WEIGHT INPUT
   ============================================= */
.weight-input {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--border);
}

.weight-input label {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

.weight-input input {
  background: var(--bg-primary);
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 0.5rem;
  width: 80px;
  font-family: inherit;
  font-size: 1.1rem;
  border-radius: 4px;
  text-align: center;
}

.weight-input input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: var(--glow);
}

.weight-input .unit {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

/* Weight Controls (+/- buttons) */
.weight-controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.weight-btn {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  border: 1px solid var(--accent);
  background: transparent;
  color: var(--accent);
  font-size: 1.2rem;
  font-family: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--transition);
}

.weight-btn:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.weight-btn:active {
  transform: scale(0.95);
}

.suggested-hint {
  font-size: 0.9rem;
  color: var(--text-secondary);
  font-style: italic;
  margin-left: 0.5rem;
}

/* =============================================
   FEEDBACK SECTION
   ============================================= */
.feedback-section {
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--border);
}

.feedback-toggle {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  padding: 0.4rem 0.75rem;
  font-size: 0.85rem;
  font-family: inherit;
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition);
}

.feedback-toggle:hover {
  border-color: var(--accent);
  color: var(--accent);
}

.feedback-content {
  display: none;
  margin-top: 0.75rem;
}

.feedback-section.expanded .feedback-content {
  display: block;
}

.feedback-section.expanded .feedback-toggle {
  border-color: var(--accent);
  color: var(--accent);
}

/* Difficulty Input */
.difficulty-input {
  margin-bottom: 0.75rem;
}

.difficulty-input label {
  font-size: 0.95rem;
  color: var(--text-secondary);
  display: block;
  margin-bottom: 0.5rem;
}

.difficulty-buttons {
  display: flex;
  gap: 0.5rem;
}

.difficulty-btn {
  flex: 1;
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  padding: 0.5rem 0.25rem;
  font-size: 0.85rem;
  font-family: inherit;
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.difficulty-btn:hover {
  border-color: var(--text-primary);
  color: var(--text-primary);
}

.difficulty-btn[data-difficulty="failed"] {
  border-color: var(--danger);
  color: var(--danger);
  opacity: 0.7;
}

.difficulty-btn[data-difficulty="failed"]:hover,
.difficulty-btn[data-difficulty="failed"].selected {
  background: var(--danger);
  color: var(--bg-primary);
  opacity: 1;
}

.difficulty-btn[data-difficulty="easy"] {
  border-color: var(--text-secondary);
  color: var(--text-secondary);
}

.difficulty-btn[data-difficulty="easy"]:hover,
.difficulty-btn[data-difficulty="easy"].selected {
  background: var(--text-secondary);
  color: var(--bg-primary);
}

.difficulty-btn[data-difficulty="good"] {
  border-color: var(--accent);
  color: var(--accent);
}

.difficulty-btn[data-difficulty="good"]:hover,
.difficulty-btn[data-difficulty="good"].selected {
  background: var(--accent);
  color: var(--bg-primary);
}

.difficulty-btn[data-difficulty="hard"] {
  border-color: var(--warning);
  color: var(--warning);
}

.difficulty-btn[data-difficulty="hard"]:hover,
.difficulty-btn[data-difficulty="hard"].selected {
  background: var(--warning);
  color: var(--bg-primary);
}

/* Failed Details */
.failed-details {
  display: none;
  margin-top: 0.75rem;
  padding: 0.75rem;
  background: rgba(255, 68, 68, 0.1);
  border: 1px solid var(--danger);
  border-radius: 4px;
}

.failed-details.visible {
  display: block;
}

.slider-group {
  margin-bottom: 0.5rem;
}

.slider-group:last-child {
  margin-bottom: 0;
}

.slider-group label {
  display: block;
  font-size: 0.9rem;
  color: var(--text-secondary);
  margin-bottom: 0.25rem;
}

.slider-value {
  color: var(--danger);
  font-weight: bold;
}

.failed-set-slider,
.failed-rep-slider {
  width: 100%;
  height: 6px;
  -webkit-appearance: none;
  appearance: none;
  background: var(--border);
  border-radius: 3px;
  outline: none;
}

.failed-set-slider::-webkit-slider-thumb,
.failed-rep-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 18px;
  height: 18px;
  background: var(--danger);
  border-radius: 50%;
  cursor: pointer;
}

.failed-set-slider::-moz-range-thumb,
.failed-rep-slider::-moz-range-thumb {
  width: 18px;
  height: 18px;
  background: var(--danger);
  border-radius: 50%;
  cursor: pointer;
  border: none;
}

/* Notes Input */
.notes-input {
  margin-top: 0.75rem;
}

.notes-field {
  width: 100%;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 0.5rem;
  font-family: inherit;
  font-size: 0.95rem;
  border-radius: 4px;
  resize: vertical;
  min-height: 2.5rem;
  max-height: 6rem;
}

.notes-field:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: var(--glow);
}

.notes-field::placeholder {
  color: var(--text-secondary);
  opacity: 0.6;
}

/* =============================================
   EXERCISE TIMER
   ============================================= */
.timer-section {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--border);
}

.timer-widget {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 0.4rem 0.6rem;
  flex: 1 1 14rem;
  min-width: 0;
}

.timer-label {
  font-size: 0.7rem;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  flex-shrink: 0;
}

.timer-display {
  font-size: 1.1rem;
  font-weight: bold;
  color: var(--accent);
  font-variant-numeric: tabular-nums;
  min-width: 2.5em;
  text-align: center;
}

.timer-display.timer-done {
  color: var(--accent);
  text-shadow: var(--glow);
}

.timer-start-pause,
.timer-reset {
  background: transparent;
  border: 1px solid var(--accent);
  color: var(--accent);
  padding: 0.2rem 0.5rem;
  font-size: 0.75rem;
  font-family: inherit;
  border-radius: 3px;
  cursor: pointer;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  flex-shrink: 0;
}

.timer-start-pause:hover,
.timer-reset:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.timer-start-pause:disabled {
  opacity: 0.5;
  cursor: default;
}

.timer-start-pause:disabled:hover {
  background: transparent;
  color: var(--accent);
}

.timer-reset {
  border-color: var(--border);
  color: var(--text-secondary);
}

.timer-reset:hover {
  border-color: var(--text-secondary);
  background: var(--text-secondary);
  color: var(--bg-primary);
}

/* =============================================
   REST DAY
   ============================================= */
#rest-day {
  text-align: center;
  padding: 3rem 1rem;
}

#rest-day h2 {
  color: var(--accent);
  font-size: 2rem;
  margin-bottom: 1rem;
}

#rest-day p {
  color: var(--text-secondary);
}

/* =============================================
   FOOTER
   ============================================= */
footer {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  background: var(--bg-secondary);
  padding: 1rem;
  display: flex;
  gap: 0.5rem;
  border-top: 1px solid var(--border);
  box-shadow: var(--shadow);
}

.btn-primary {
  flex: 1;
  background: var(--accent);
  color: var(--bg-primary);
  border: none;
  padding: 1rem;
  font-size: 1.1rem;
  font-weight: bold;
  font-family: inherit;
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.1em;
}

.btn-primary:hover {
  background: var(--accent-dim);
  box-shadow: var(--glow);
}

.btn-primary:active {
  transform: scale(0.98);
}

.btn-secondary {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  padding: 1rem;
  font-size: 1rem;
  font-family: inherit;
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition);
}

.btn-secondary:hover {
  border-color: var(--danger);
  color: var(--danger);
}

/* =============================================
   VIDEO MODAL
   ============================================= */
.modal {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.9);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 200;
  padding: 1rem;
}

.modal-content {
  background: var(--bg-card);
  border: 1px solid var(--accent);
  border-radius: var(--radius);
  width: 100%;
  max-width: 640px;
  position: relative;
  box-shadow: var(--shadow);
}

.close-btn {
  position: absolute;
  top: -40px;
  right: 0;
  background: transparent;
  border: none;
  color: var(--text-primary);
  font-size: 2rem;
  cursor: pointer;
  padding: 0.5rem;
}

#video-container {
  position: relative;
  padding-bottom: 56.25%;
  height: 0;
  overflow: hidden;
}

#video-container iframe {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  border: none;
  border-radius: var(--radius);
}

/* =============================================
   SETTINGS MODAL
   ============================================= */
.settings-modal {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.85);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 300;
  padding: 1rem;
}

.settings-content {
  background: var(--bg-card);
  border: 1px solid var(--accent);
  border-radius: var(--radius);
  width: 100%;
  max-width: 320px;
  padding: 1.5rem;
  box-shadow: var(--shadow);
  max-height: 90vh;
  overflow-y: auto;
}

.settings-title {
  font-size: 1.2rem;
  color: var(--accent);
  margin-bottom: 1.25rem;
  text-align: center;
  letter-spacing: 0.1em;
}

.theme-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}

.theme-option {
  background: var(--bg-secondary);
  border: 2px solid var(--border);
  border-radius: 6px;
  padding: 1rem 0.5rem;
  cursor: pointer;
  text-align: center;
  transition: all var(--transition);
}

.theme-option:hover {
  border-color: var(--text-secondary);
}

.theme-option.active {
  border-color: var(--accent);
}

.theme-swatch {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  margin: 0 auto 0.5rem;
  border: 2px solid var(--border);
}

.theme-option[data-theme="cyberpunk"] .theme-swatch {
  background: #00ff88;
}

.theme-option[data-theme="material"] .theme-swatch {
  background: #009688;
}

.theme-option[data-theme="ocean"] .theme-swatch {
  background: #2196f3;
}

.theme-option[data-theme="ember"] .theme-swatch {
  background: #ff7043;
}

.theme-name {
  font-size: 0.85rem;
  color: var(--text-primary);
  text-transform: capitalize;
}

/* =============================================
   PROFILE EDITOR
   ============================================= */
.profile-section {
  border-top: 1px solid var(--border);
  padding-top: 1.25rem;
  margin-top: 1.25rem;
}

.profile-section-label {
  font-size: 0.95rem;
  color: var(--text-secondary);
  display: block;
  margin-bottom: 0.75rem;
}

.profile-fields {
  display: flex;
  flex-direction: column;
  gap: 0.6rem;
}

.profile-row label {
  display: block;
  font-size: 0.75rem;
  color: var(--text-secondary);
  margin-bottom: 0.2rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.profile-row input {
  width: 100%;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 6px;
  color: var(--text-primary);
  padding: 0.45rem 0.6rem;
  font-size: 0.85rem;
  font-family: inherit;
  box-sizing: border-box;
  transition: border-color var(--transition);
}

.profile-row input:focus {
  outline: none;
  border-color: var(--accent);
}

.profile-row-pair {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.6rem;
}

.mode-toggle-section {
  border-top: 1px solid var(--border);
  padding-top: 1.25rem;
}

.mode-toggle-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.mode-label {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

.mode-toggle {
  display: flex;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 20px;
  padding: 2px;
}

.mode-btn {
  background: transparent;
  border: none;
  color: var(--text-secondary);
  padding: 0.4rem 0.75rem;
  font-size: 1rem;
  cursor: pointer;
  border-radius: 16px;
  transition: all var(--transition);
}

.mode-btn.active {
  background: var(--accent);
  color: var(--bg-primary);
}

/* =============================================
   DATA IMPORT/EXPORT
   ============================================= */
.data-section {
  border-top: 1px solid var(--border);
  padding-top: 1.25rem;
  margin-top: 1.25rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.data-label {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

.data-buttons {
  display: flex;
  gap: 0.5rem;
}

.data-btn {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  padding: 0.4rem 0.75rem;
  font-size: 0.8rem;
  cursor: pointer;
  border-radius: 6px;
  transition: all var(--transition);
  letter-spacing: 0.05em;
}

.data-btn:hover {
  border-color: var(--accent);
  color: var(--accent);
}

/* =============================================
   UTILITY CLASSES
   ============================================= */
.hidden {
  display: none !important;
}

/* =============================================
   SCROLLBAR
   ============================================= */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: var(--bg-primary);
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--accent-dim);
}

